    required this.region,
    required this.publicUrl,
  });
}

Future<S3UploadResult> uploadFileToS3(File file, String key) async {
  final bytes = await file.readAsBytes();
  final contentType = _mimeTypeFromPath(file.path);
  final host = '$s3BucketName.s3.$awsRegion.amazonaws.com';
  final uri = Uri.parse('https://$host/$key');
  final payloadHash = sha256.convert(bytes).toString();
  final amzDate = _amzDate(DateTime.now().toUtc());
  final dateStamp = amzDate.substring(0, 8);

  final canonicalHeaders =
      'host:$host\n'
      'x-amz-content-sha256:$payloadHash\n'
      'x-amz-date:$amzDate\n';

  final signedHeaders = 'host;x-amz-content-sha256;x-amz-date';
  final canonicalRequest =
      'PUT\n'
      '/$key\n'
      '\n'
      '$canonicalHeaders\n'
      '$signedHeaders\n'
      '$payloadHash';

  final credentialScope = '$dateStamp/$awsRegion/s3/aws4_request';
  final stringToSign =
      'AWS4-HMAC-SHA256\n'
      '$amzDate\n'
      '$credentialScope\n'
      '${sha256.convert(utf8.encode(canonicalRequest)).toString()}';

  final signingKey = _getSignatureKey(awsSecretAccessKey, dateStamp, awsRegion, 's3');
  final signature = _hmacHex(signingKey, stringToSign);

  final authorizationHeader =
      'AWS4-HMAC-SHA256 Credential=$awsAccessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

  final response = await http.put(
    uri,
    headers: {
      'Content-Type': contentType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      'Authorization': authorizationHeader,
    },
    body: bytes,
  );

  if (response.statusCode < 200 || response.statusCode >= 300) {
    throw HttpException('S3 upload failed (${response.statusCode}): ${response.body}');
  }

  return S3UploadResult(
    bucket: s3BucketName,
    key: key,
    region: awsRegion,
    publicUrl: 'https://$host/$key',
  );
}

Future<String> analyzeImageWithVision(File file) async {
  final bytes = await file.readAsBytes();
  final base64Image = base64Encode(bytes);

  final url = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$gcpVisionApiKey');
  final response = await http.post(
    url,
    headers: {'Content-Type': 'application/json'},
    body: jsonEncode({
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 10},
          ],
        },
      ],
    }),
  );

  if (response.statusCode < 200 || response.statusCode >= 300) {
    throw HttpException('Vision API failed (${response.statusCode}): ${response.body}');
  }

  final decoded = jsonDecode(response.body) as Map<String, dynamic>;
  final responses = decoded['responses'] as List<dynamic>? ?? [];
  if (responses.isEmpty) return 'No analysis returned.';

  final r = responses.first as Map<String, dynamic>;
  final buffer = StringBuffer();

  final labelAnnotations = (r['labelAnnotations'] as List<dynamic>?) ?? [];
  if (labelAnnotations.isNotEmpty) {
    buffer.writeln('Labels:');
    for (final item in labelAnnotations.take(10)) {
      final m = item as Map<String, dynamic>;
      buffer.writeln('- ${m['description']} (${((m['score'] ?? 0) as num).toStringAsFixed(2)})');
    }
    buffer.writeln();
  }

  final textAnnotations = (r['textAnnotations'] as List<dynamic>?) ?? [];
  if (textAnnotations.isNotEmpty) {
    buffer.writeln('Detected Text:');
    final text = (textAnnotations.first as Map<String, dynamic>)['description']?.toString() ?? '';
    buffer.writeln(text);
    buffer.writeln();
  }

  final localizedObjectAnnotations = (r['localizedObjectAnnotations'] as List<dynamic>?) ?? [];
  if (localizedObjectAnnotations.isNotEmpty) {
    buffer.writeln('Objects:');
    for (final item in localizedObjectAnnotations.take(10)) {
      final m = item as Map<String, dynamic>;
      buffer.writeln('- ${m['name']} (${((m['score'] ?? 0) as num).toStringAsFixed(2)})');
    }
    buffer.writeln();
  }

  final safeSearchAnnotation = r['safeSearchAnnotation'] as Map<String, dynamic>?;
  if (safeSearchAnnotation != null) {
    buffer.writeln('Safe Search:');
    safeSearchAnnotation.forEach((key, value) {
      buffer.writeln('- $key: $value');
    });
  }

  return buffer.isEmpty ? 'No notable annotations found.' : buffer.toString().trim();
}

String _mimeTypeFromPath(String path) {
  final lower = path.toLowerCase();
  if (lower.endsWith('.png')) return 'image/png';
  if (lower.endsWith('.webp')) return 'image/webp';
  if (lower.endsWith('.gif')) return 'image/gif';
  if (lower.endsWith('.jpeg') || lower.endsWith('.jpg')) return 'image/jpeg';
  if (lower.endsWith('.heic')) return 'image/heic';
  return 'application/octet-stream';
}

String _extensionFromPath(String path) {
  final lower = path.toLowerCase();
  if (lower.endsWith('.png')) return 'png';
  if (lower.endsWith('.webp')) return 'webp';
  if (lower.endsWith('.gif')) return 'gif';
  if (lower.endsWith('.jpeg')) return 'jpeg';
  if (lower.endsWith('.jpg')) return 'jpg';
  if (lower.endsWith('.heic')) return 'heic';
  return 'jpg';
}

String _randomSuffix(int length) {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  final rand = Random.secure();
  return List.generate(length, (_) => chars[rand.nextInt(chars.length)]).join();
}

String _amzDate(DateTime dtUtc) {
  String two(int v) => v.toString().padLeft(2, '0');
  return '${dtUtc.year}${two(dtUtc.month)}${two(dtUtc.day)}T${two(dtUtc.hour)}${two(dtUtc.minute)}${two(dtUtc.second)}Z';
}

List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
  final kDate = Hmac(sha256, utf8.encode('AWS4$key')).convert(utf8.encode(dateStamp)).bytes;
  final kRegion = Hmac(sha256, kDate).convert(utf8.encode(regionName)).bytes;
  final kService = Hmac(sha256, kRegion).convert(utf8.encode(serviceName)).bytes;
  final kSigning = Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
  return kSigning;
}

String _hmacHex(List<int> key, String data) {
  return Hmac(sha256, key).convert(utf8.encode(data)).toString();
}